    if (DL.getTypeStoreSize(SI->getValueOperand()->getType()).getFixedSize() != ElementSize) {
      return false;
    }
  }

  // Check if offsets form a contiguous sequence
  int64_t MinOffset = Offsets[0];
  int64_t MaxOffset = Offsets.back();
  uint64_t ExpectedRange = (Stores.size() - 1) * ElementSize;

  // The range should exactly match the expected contiguous range
  if (static_cast<uint64_t>(MaxOffset - MinOffset) != ExpectedRange) {
    return false;
